#ifndef TOP_K_TOP_P_SAMPLING_FROM_PROBS_V129280_KERNEL_H
#define TOP_K_TOP_P_SAMPLING_FROM_PROBS_V129280_KERNEL_H

#include <cstdint>
#include <cuda_runtime.h>

constexpr int VOCAB_SIZE_V129280 = 129280;

// Launches sampling kernel.
// probs:   [B, V] float32 (softmax probabilities)
// top_k:   [B]    int32
// top_p:   [B]    float32
// samples: [B]    int64
void top_k_top_p_sampling_from_probs_v129280_launch(
    const float* probs,
    const int32_t* top_k,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    uint64_t seed,
    cudaStream_t stream);

#endif // TOP_K_TOP_P_SAMPLING_FROM_PROBS_V129280_KERNEL_H

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>

#define FULL_MASK 0xFFFFFFFFu

// ---------------- RNG (stateless per (b, pass, counter)) ----------------
__device__ __forceinline__ uint64_t splitmix64_stateless(uint64_t x) {
  x += 0x9E3779B97F4A7C15ULL;
  x = (x ^ (x >> 30)) * 0xBF58476D1CE4E5B9ULL;
  x = (x ^ (x >> 27)) * 0x94D049BB133111EBULL;
  x = x ^ (x >> 31);
  return x;
}

// uniform in (0,1], avoid 0
__device__ __forceinline__ float u01_from_u32(uint32_t x) {
  // 24-bit mantissa in [1, 2^24-1]
  uint32_t mant = (x >> 8) | 1u;
  return (float)mant * (1.0f / 16777216.0f);
}

// ---------------- warp/block reductions ----------------
__device__ __forceinline__ float warpReduceSum(float v) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(FULL_MASK, v, offset);
  }
  return v;
}

template <int BLOCK>
__device__ __forceinline__ float blockReduceSum(float v) {
  static_assert((BLOCK % 32) == 0, "BLOCK must be multiple of 32");
  __shared__ float shared[32];
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;

  v = warpReduceSum(v);
  if (lane == 0) shared[wid] = v;
  __syncthreads();

  v = (threadIdx.x < (BLOCK >> 5)) ? shared[lane] : 0.0f;
  if (wid == 0) v = warpReduceSum(v);
  return __shfl_sync(FULL_MASK, v, 0);
}

struct PairMax {
  float v;
  int i;
};

__device__ __forceinline__ PairMax pairMax(const PairMax& a, const PairMax& b) {
  if (b.v > a.v) return b;
  if (b.v < a.v) return a;
  // tie-break: smaller index (matches typical argmax behavior)
  return (b.i < a.i) ? b : a;
}

__device__ __forceinline__ PairMax warpReduceMaxPair(PairMax p) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    PairMax o;
    o.v = __shfl_down_sync(FULL_MASK, p.v, offset);
    o.i = __shfl_down_sync(FULL_MASK, p.i, offset);
    p = pairMax(p, o);
  }
  return p;
}

template <int BLOCK>
__device__ __forceinline__ PairMax blockReduceMaxPair(PairMax p) {
  static_assert((BLOCK % 32) == 0, "BLOCK must be multiple of 32");
  __shared__ PairMax shared[32];
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;

  p = warpReduceMaxPair(p);
  if (lane == 0) shared[wid] = p;
  __syncthreads();

  PairMax out;
  out.v = -1.0f;
  out.i = 0;

  if (wid == 0) {
    out = (threadIdx.x < (BLOCK >> 5)) ? shared[lane] : out;
    out = warpReduceMaxPair(out);
  }
  out.v = __shfl_sync(FULL_MASK, out.v, 0);
  out.i = __shfl_sync(FULL_MASK, out.i, 0);
  return out;
}

// ---------------- selection helpers ----------------
// Find k-th largest value threshold using repeated block-wide max scans.
// Complexity: O(k * V). This is acceptable for small k (typical decoding).
template <int BLOCK>
__device__ __forceinline__ float kth_largest_threshold_scan(
    const float* __restrict__ row, int k) {
  // k is clamped to [1, V]
  float prev_thr = CUDART_INF_F; // ignore > prev_thr
  float thr = -CUDART_INF_F;

  for (int it = 0; it < k; ++it) {
    PairMax local{-CUDART_INF_F, 0};
    for (int j = threadIdx.x; j < VOCAB_SIZE_V129280; j += BLOCK) {
      float v = row[j];
      // strictly less than prev_thr to avoid picking same value repeatedly
      if (v < prev_thr) {
        local = pairMax(local, PairMax{v, j});
      }
    }
    PairMax g = blockReduceMaxPair<BLOCK>(local);
    thr = g.v;
    prev_thr = thr;
    // If distribution has many ties and we hit -inf, break
    if (!isfinite(thr)) break;
    __syncthreads();
  }
  return thr;
}

template <int BLOCK>
__global__ void top_k_top_p_sampling_from_probs_v129280_kernel(
    const float* __restrict__ probs,   // [B,V]
    const int32_t* __restrict__ top_k, // [B]
    const float* __restrict__ top_p,   // [B]
    int64_t* __restrict__ samples,     // [B]
    int B,
    uint64_t seed) {

  int b = (int)blockIdx.x;
  if (b >= B) return;

  const float* row = probs + (size_t)b * (size_t)VOCAB_SIZE_V129280;

  int k = top_k[b];
  float p = top_p[b];

  // Clamp k to [0, V]
  if (k < 0) k = 0;
  if (k > VOCAB_SIZE_V129280) k = VOCAB_SIZE_V129280;

  // Compute argmax always (needed for p<=0 path).
  PairMax lmx{-CUDART_INF_F, 0};
  for (int j = threadIdx.x; j < VOCAB_SIZE_V129280; j += BLOCK) {
    float v = row[j];
    lmx = pairMax(lmx, PairMax{v, j});
  }
  PairMax gmx = blockReduceMaxPair<BLOCK>(lmx);

  // Reference: top-k applied before top-p, but if p<=0 it returns argmax after top-k.
  // If p<=0: we must argmax after top-k filtering if k in (0,V).
  if (p <= 0.0f) {
    int out = gmx.i;
    if (k > 0 && k < VOCAB_SIZE_V129280) {
      // find threshold for top-k and argmax within it (argmax is already within).
      // But if argmax not in top-k? impossible. So out is correct.
      // (No-op; kept for clarity)
      (void)k;
    }
    if (threadIdx.x == 0) samples[b] = (int64_t)out;
    return;
  }

  // ------------- Top-k threshold (exact for small k) -------------
  float kth_thr = -CUDART_INF_F;
  bool use_topk = (k > 0 && k < VOCAB_SIZE_V129280);
  if (use_topk) {
    kth_thr = kth_largest_threshold_scan<BLOCK>(row, k);
  }

  // ------------- Pass 1: compute kept sum and (if needed) top-p threshold -------------
  // If p>=1 => no top-p filtering, only top-k.
  bool use_topp = (p < 1.0f);

  // We will build nucleus by finding smallest threshold t such that sum_{v>=t} kept_prob >= p * kept_sum.
  // Implemented as iterative max peeling like top-k, but stopping when cumulative meets target.
  float kept_sum_local = 0.0f;
  for (int j = threadIdx.x; j < VOCAB_SIZE_V129280; j += BLOCK) {
    float v = row[j];
    if (use_topk) {
      if (v < kth_thr) continue;
    }
    kept_sum_local += v;
  }
  float kept_sum = blockReduceSum<BLOCK>(kept_sum_local);

  // If degenerate, fall back to argmax.
  if (!(kept_sum > 0.0f) || !isfinite(kept_sum)) {
    if (threadIdx.x == 0) samples[b] = (int64_t)gmx.i;
    return;
  }

  float topp_thr = -CUDART_INF_F;
  float nucleus_sum = kept_sum;

  if (use_topp) {
    float target = p * kept_sum;
    // Follow reference-like behavior: keep at least 1 token.
    float cum = 0.0f;
    float prev_thr = CUDART_INF_F;
    float last_thr = -CUDART_INF_F;

    // Safety cap: we should never need more than V iterations, but cap to avoid infinite loops on NaNs.
    for (int it = 0; it < VOCAB_SIZE_V129280; ++it) {
      // pick next max under prev_thr among (top-k kept)
      PairMax local{-CUDART_INF_F, 0};
      for (int j = threadIdx.x; j < VOCAB_SIZE_V129280; j += BLOCK) {
        float v = row[j];
        if (use_topk && v < kth_thr) continue;
        if (v < prev_thr) local = pairMax(local, PairMax{v, j});
      }
      PairMax g = blockReduceMaxPair<BLOCK>(local);
      float vsel = g.v;

      if (!(vsel > -CUDART_INF_F) || !isfinite(vsel)) {
        // nothing else to add
        break;
      }

      cum += vsel;
      last_thr = vsel;
      prev_thr = vsel;
      __syncthreads();

      // Keep at least 1 element: after first, we can stop when cum >= target.
      if (it >= 0 && cum >= target) {
        topp_thr = last_thr;
        break;
      }
    }

    // If we never reached target, keep everything (no top-p removal effectively)
    if (!(topp_thr > -CUDART_INF_F) || !isfinite(topp_thr)) {
      use_topp = false;
      topp_thr = -CUDART_INF_F;
      nucleus_sum = kept_sum;
    } else {
      // Compute nucleus sum for renorm: include v > topp_thr, and also include v == topp_thr?
      // Reference keeps all tokens up to cut boundary in sorted order; with ties it's tricky.
      // We approximate by keeping v >= topp_thr (may keep extra ties; acceptable & deterministic).
      float nuc_local = 0.0f;
      for (int j = threadIdx.x; j < VOCAB_SIZE_V129280; j += BLOCK) {
        float v = row[j];
        if (use_topk && v < kth_thr) continue;
        if (v >= topp_thr) nuc_local += v;
      }
      nucleus_sum = blockReduceSum<BLOCK>(nuc_local);
      if (!(nucleus_sum > 0.0f) || !isfinite(nucleus_sum)) {
        if (threadIdx.x == 0) samples[b] = (int64_t)gmx.i;
        return;
      }
    }
  }

  // ------------- Sampling from filtered+renorm distribution -------------
  uint64_t s = splitmix64_stateless(seed ^ (0x9E3779B97F4A7C15ULL * (uint64_t)(b + 1)));
  float u = u01_from_u32((uint32_t)(s & 0xFFFFFFFFu));

  float inv = 1.0f / nucleus_sum;

  __shared__ int out_idx_s;
  __shared__ float running;
  __shared__ float tile_prefix;

  if (threadIdx.x == 0) {
    out_idx_s = gmx.i; // fallback
    running = 0.0f;
  }
  __syncthreads();

  for (int base = 0; base < VOCAB_SIZE_V129280; base += BLOCK) {
    int j = base + threadIdx.x;

    float v = 0.0f;
    if (j < VOCAB_SIZE_V129280) {
      float pj = row[j];
      bool keep = true;
      if (use_topk && pj < kth_thr) keep = false;
      if (use_topp && pj < topp_thr) keep = false;
      v = keep ? (pj * inv) : 0.0f;
    }

    float tile_sum = blockReduceSum<BLOCK>(v);

    if (threadIdx.x == 0) tile_prefix = running;
    __syncthreads();

    float before = tile_prefix;
    float after  = before + tile_sum;

    if (threadIdx.x == 0) running = after;
    __syncthreads();

    if (u <= after) {
      if (threadIdx.x == 0) {
        float c = before;
        int out = min(base, VOCAB_SIZE_V129280 - 1);
        int end = min(base + BLOCK, VOCAB_SIZE_V129280);
        for (int jj = base; jj < end; ++jj) {
          float pj = row[jj];
          bool keep = true;
          if (use_topk && pj < kth_thr) keep = false;
          if (use_topp && pj < topp_thr) keep = false;
          if (!keep) continue;
          c += pj * inv;
          if (u <= c) { out = jj; break; }
        }
        out_idx_s = out;
      }
      __syncthreads();
      break;
    }
  }

  if (threadIdx.x == 0) samples[b] = (int64_t)out_idx_s;
}

void top_k_top_p_sampling_from_probs_v129280_launch(
    const float* probs,
    const int32_t* top_k,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    uint64_t seed,
    cudaStream_t stream) {

  // One block per batch row.
  // A800 (SM80) sweet spot: 256 or 512. 256 tends to reduce register pressure here.
  constexpr int BLOCK = 256;
  dim3 grid((unsigned)batch_size);
  dim3 block(BLOCK);

  top_k_top_p_sampling_from_probs_v129280_kernel<BLOCK>
      <<<grid, block, 0, stream>>>(probs, top_k, top_p, samples, batch_size, seed);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include <cstdint>
#include <sstream>
#include <stdexcept>
#include <string>

#include "kernel.h"

static void check_defined(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss;
    oss << name << " must be a defined tensor";
    throw std::runtime_error(oss.str());
  }
}
static void check_cuda(const torch::Tensor& t, const char* name) {
  if (!t.device().is_cuda()) {
    std::ostringstream oss;
    oss << name << " must be a CUDA tensor";
    throw std::runtime_error(oss.str());
  }
}
static void check_1d(const torch::Tensor& t, const char* name) {
  if (t.dim() != 1) {
    std::ostringstream oss;
    oss << name << " must be 1D";
    throw std::runtime_error(oss.str());
  }
}
static void check_2d(const torch::Tensor& t, const char* name) {
  if (t.dim() != 2) {
    std::ostringstream oss;
    oss << name << " must be 2D";
    throw std::runtime_error(oss.str());
  }
}

torch::Tensor run(torch::Tensor probs, torch::Tensor top_k, torch::Tensor top_p) {
  check_defined(probs, "probs");
  check_defined(top_k, "top_k");
  check_defined(top_p, "top_p");

  check_cuda(probs, "probs");
  check_cuda(top_k, "top_k");
  check_cuda(top_p, "top_p");

  if (probs.dtype() != torch::kFloat32) throw std::runtime_error("probs must be torch.float32");
  if (top_k.dtype() != torch::kInt32) throw std::runtime_error("top_k must be torch.int32");
  if (top_p.dtype() != torch::kFloat32) throw std::runtime_error("top_p must be torch.float32");

  check_2d(probs, "probs");
  check_1d(top_k, "top_k");
  check_1d(top_p, "top_p");

  const int64_t B = probs.size(0);
  const int64_t V = probs.size(1);

  if (V != VOCAB_SIZE_V129280) {
    std::ostringstream oss;
    oss << "vocab_size must be " << VOCAB_SIZE_V129280 << " but got " << V;
    throw std::runtime_error(oss.str());
  }
  if (top_k.size(0) != B || top_p.size(0) != B) {
    throw std::runtime_error("top_k/top_p must have shape [batch_size] matching probs.size(0)");
  }

  if (B < 0 || B > INT32_MAX) {
    throw std::runtime_error("batch_size is out of supported range");
  }

  if (!probs.is_contiguous()) probs = probs.contiguous();
  if (!top_k.is_contiguous()) top_k = top_k.contiguous();
  if (!top_p.is_contiguous()) top_p = top_p.contiguous();

  auto samples = torch::empty({B}, torch::TensorOptions().dtype(torch::kInt64).device(probs.device()));

  const float* probs_ptr = probs.data_ptr<float>();
  const int32_t* topk_ptr = top_k.data_ptr<int32_t>();
  const float* topp_ptr = top_p.data_ptr<float>();
  int64_t* out_ptr = samples.data_ptr<int64_t>();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  int device = -1;
  cudaError_t derr = cudaGetDevice(&device);
  if (derr != cudaSuccess) throw std::runtime_error("cudaGetDevice failed");

  // Deterministic-ish seed (per call) while still varying across tensors/devices.
  uint64_t seed = 0xD2B74407B1CE6E93ULL;
  seed ^= (uint64_t)(uintptr_t)probs_ptr;
  seed ^= (uint64_t)(uintptr_t)topk_ptr * 0x9E3779B97F4A7C15ULL;
  seed ^= (uint64_t)(uintptr_t)topp_ptr * 0xBF58476D1CE4E5B9ULL;
  seed ^= (uint64_t)(uintptr_t)out_ptr  * 0x94D049BB133111EBULL;
  seed ^= (uint64_t)(uint32_t)device    * 0xA24BAED4963EE407ULL;
  seed ^= (uint64_t)B                  * 0xD1342543DE82EF95ULL;

  top_k_top_p_sampling_from_probs_v129280_launch(
      probs_ptr, topk_ptr, topp_ptr, out_ptr, (int)B, seed, stream);

  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch error: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  // Keep synchronize to surface runtime errors in this benchmark harness.
  err = cudaDeviceSynchronize();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA error after kernel: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return samples;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function",
        py::arg("probs"), py::arg("top_k"), py::arg("top_p"));
}
